        // Arrange & Act & Assert for Visto = 0 (typically female)
        var filtroFemale = new FilterProSucumbencia
        {
            Visto = 0
        };
        var resultFemale = _serviceS.WFiltroProSucumbencia(filtroFemale);
        resultFemale.Should().NotBeNull();
        var femaleParam = resultFemale.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBProSucumbenciaDicInfo.Visto}");
        femaleParam.Should().NotBeNull();
        femaleParam.Value.Should().Be(0);
        // Arrange & Act & Assert for Visto = 1 (typically male)
        var filtroMale = new FilterProSucumbencia
        {
            Visto = 1
        };
        var resultMale = _serviceS.WFiltroProSucumbencia(filtroMale);
        resultMale.Should().NotBeNull();
        var maleParam = resultMale.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBProSucumbenciaDicInfo.Visto}");
        maleParam.Should().NotBeNull();
        maleParam.Value.Should().Be(1);
    }

    [Fact]
    public void WFiltro_VistoAsFirstFilter_ShouldNotIncludeLogicalOperatorInWhereClause()
    {
        // Arrange
        var filtro = new FilterProSucumbencia
        {
            Visto = 1,
            LogicalOperator = " AND "
        };
        // Act
        var result = _serviceS.WFiltroProSucumbencia(filtro);
        // Assert
        result.Should().NotBeNull();
        result.Value.where.Should().StartWith($"[{DBProSucumbenciaDicInfo.PTabelaNome}].[{DBProSucumbenciaDicInfo.Visto}] = @{DBProSucumbenciaDicInfo.Visto}");
        result.Value.where.Should().NotStartWith(" AND ");
    }

